-- Full database schema + content seed for One Global Logistics Qatar
-- Content is stored PAGE-WISE: one row per content key in site_content.
-- Images are stored as BLOBs in site_images, served via GET /api/image/:id.
-- Content values are hex-encoded to avoid quote/escaping issues with the JSON payload.

CREATE TABLE IF NOT EXISTS site_content (
  page VARCHAR(50) PRIMARY KEY,
  content LONGTEXT NOT NULL,
  updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP
);

CREATE TABLE IF NOT EXISTS site_images (
  id INT AUTO_INCREMENT PRIMARY KEY,
  filename VARCHAR(255) NOT NULL,
  mimetype VARCHAR(100) NOT NULL,
  size INT NOT NULL,
  data LONGBLOB NOT NULL,
  uploaded_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

